 10→
 11→type StyledButtonProperties = {
 12→  $clear: boolean
 13→  $large: boolean
 14→  $withIcon: boolean
 15→  $round: boolean
 16→}
 17→
 18→const StyledButton = styled.button<StyledButtonProperties>(
 19→  ({ $clear, $large, $round, $withIcon, theme: { color, boxShadow, borderRadius } }) => css`
 20→    outline: none;
 21→    border: 0;
 22→    font-family: 'Hind';
 23→    border-radius: ${$round ? borderRadius.xl : borderRadius.xs};
 24→    display: inline-flex;
 25→    align-items: center;
 26→    justify-content: center;
 27→    padding: ${$withIcon ? '0.7rem' : $large ? '1.125rem 1rem' : '0.875rem 1rem'};
 28→    color: ${$clear ? color.primaryText : color.buttonText};
 29→
 30→    transition: box-shadow 150ms ease-in;
 31→    z-index: 1;
 32→    background-color: ${$clear ? color.buttonClear : color.buttonPrimary};
 33→
 34→    &:hover {
 35→      cursor: pointer;
 36→      background-color: ${$clear ? color.buttonClearHover : color.buttonPrimaryHover};
 37→    }
 38→
 39→    &:focus {
 40→      box-shadow: ${boxShadow.outerBorder};
 41→    }
 42→
 43→    &:disabled {
 44→      background-color: ${$clear ? color.buttonClear : color.buttonPrimary};
 45→      opacity: 0.4;
 46→    }
 47→
 48→    @media ${breakpoints.M} {
 49→      padding: ${$withIcon ? '1rem' : $large ? '1.125rem 1.5rem' : '0.875rem 1.5rem'};
 50→    }
 51→  `
 52→)
 53→
 54→type DefaultProperties = {
 55→  /**
 56→   * Clear button styles leaving just a text
 57→   */
 58→  clear?: boolean
 59→  round?: boolean
 60→  /**
 61→   * Is the button large?
 62→   */
 63→  large?: boolean
 64→  /**
 65→   * Does the button have an icon?
 66→   */
 67→  icon?: IconName
 68→  /**
 69→   * Size of the icon
 70→   */
 71→  iconSize?: number
 72→  /**
 73→   * Is the button disabled?
 74→   */
 75→  disabled?: boolean
 76→  /**
 77→   * Does the button have an icon?
 78→   */
 79→  children?: string | React.ReactNode
 80→  /**
 81→   * Optional click handler
 82→   */
 83→  onClick?: () => void
 84→}
 85→
 86→// Remove StyledButton props from ButtonProps to avoid duplicate props
 87→type ButtonProperties = DefaultProperties &
 88→  Omit<React.ComponentProps<'button'>, keyof DefaultProperties>
 89→
 90→/**
 91→ * Primary UI component for user interaction
 92→ */
 93→export const Button: React.FC<React.PropsWithChildren<ButtonProperties>> = ({
 94→  children,
 95→  large = false,
 96→  clear = false,
 97→  round = false,
 98→  icon,
 99→  iconSize,
100→  ...properties
101→}: ButtonProperties) => {
102→  const { color } = useTheme()
103→
104→  return (
105→    <StyledButton
106→      type="button"
107→      $large={large}
108→      $clear={clear}
109→      $round={round}
110→      $withIcon={!!icon}
111→      {...properties}
112→    >
113→      {icon && (
114→        <Icon color={clear ? color.primaryText : color.buttonText} size={iconSize} name={icon} />
115→      )}
116→      {icon && children && <Spacer />}
117→      {children}
118→    </StyledButton>
119→  )
120→}
